	bool reachable (int[0,diM-1] inp) { // true if a note can be visible by the input_node
	if (inp == 0) return ( nodeState[32].location != sN and  nodeState[1].location != sN);
	else if (inp ==1) return ( ( nodeState[6].location == sM or  nodeState[6].location == sM and  nodeState[4].location == sM or true ) and  nodeState[10].location != sN and  nodeState[1].location != sN);
	else if (inp ==2) return ( nodeState[6].location == sM and  nodeState[25].location != sN and  nodeState[1].location != sN);
	else if (inp ==3) return ( nodeState[32].location != sN and  nodeState[1].location != sN);
	else if (inp ==4) return ( ( nodeState[32].location == sM or  nodeState[6].location == sM and  nodeState[18].location == sM and  nodeState[15].location != sN or  nodeState[12].location == sM ) and  nodeState[22].location != sN and  nodeState[19].location != sN and  nodeState[1].location != sN);
	else if (inp ==5) return ( nodeState[32].location != sN and  nodeState[1].location != sN);
	else if (inp ==6) return ( nodeState[12].location != sN and  nodeState[1].location != sN);
	else if (inp ==7) return ( nodeState[6].location == sM and  nodeState[25].location != sN and  nodeState[1].location != sN);
