	int[NU,MaxUnitCost] getMinInputCost(int[0,NbStates-1] source_state, int[0,NbStates-1] target_state) {  // son état acuel et son état visé
	    int[NU,MaxUnitCost] cost:=-1; int attackerState:=-1; int[NU,MaxUnitCost] costTmp:=-1;
	    if (NbInputs <=0) return -1;
	 	for(i : int[0,diM-1] ) if (reachable(i)){
	        attackerState:=nodeState[node.in[i].node_id].location;
	        costTmp:=node.in[i].cost[attackerState][target_state];
	        if ((costTmp>=0) and ((cost<0) or (costTmp<cost))) cost:=costTmp; 
		}
	    if ( (cost+costs)<= maxCosts )	return cost; else return -1;
	}

	void updateNode (int[NU,nbNodes-1] node_id, int[0,NbStates-1] source_state,int[0,NbStates-1] target_state) {
	    int[NU,MaxUnitCost] tmp:=getMinInputCost(source_state,target_state);
	    if (tmp >0) costs:=costs+tmp;
	    nodeState[node_id].location:=target_state;
	}


	int[NU,MaxUnitCost] getLocalCost(int[0,NbStates-1] source_state, int[0,NbStates-1] target_state) {  // node qui est visé et son état acuel et son état visé
	    int[NU,MaxUnitCost] cost:=node.cost[source_state][target_state];
	    if ( (cost>=0) and ((cost+costs)<= maxCosts ))	return cost; else return -1;
	}

	void updateLocal (int[NU,nbNodes-1] node_id, int[0,NbStates-1] source_state,int[0,NbStates-1] target_state) {
	    int[NU,MaxUnitCost] tmp:=getLocalCost(source_state,target_state);
	    if (tmp >0) costs:=costs+tmp;
	    nodeState[node_id].location:=target_state;
	}


	int[NU,maxCosts] LocalVarCost(int[NU,nbNodes-1] node_id) {
	    int[NU,MaxUnitCost] cost;
	    for(i : int[0,nbVar-1] ) {
	        if ((!nodeState[node_id].locKnowledgeVar[i]) and node.locSecretVar[i] ) {
	            cost:=node.costVarGet;
	            if ((cost >=0) and (cost+costs)<=maxCosts) return cost;
	        }
	    };
	    return -1;
	}

	void setLocalVar(int[NU,nbNodes-1] node_id){
	       int[NU,MaxUnitCost] cost;
	    for(i : int[0,nbVar-1] ) {
	        if ((!nodeState[node_id].locKnowledgeVar[i]) and node.locSecretVar[i] ) {
	            cost:=node.costVarGet;
	            if ((cost >=0) and (cost+costs)<=maxCosts) {
	                costs:=costs+cost; nodeState[node_id].locKnowledgeVar[i]:=true; return;
	            }
	        }
	    }
	}

// Place local declarations here.
	const int NbInputs := 134; // per node
	const int diM = (NbInputs>0)? NbInputs : 1;
	typedef struct {
	    int[0,nbNodes-1] node_id;
	    int[0, 2] node_type; // 0 == user space component , 1 == root space component, 2 == kernel
	    int[NU,MaxUnitCost] cost[NbStates][NbStates];  //  local attacker node state, attacked node target state,  -1 not possible, external node state, target local state
	    bool locSecretVar[nbVar]; // if true, secret to be retrived here
	    int[NU,MaxUnitCost] costVarGet, costVarTransf;
	    input_t in[diM]; 
